import React, { useState, useEffect } from 'react';
import { useParams, useNavigate, useLocation } from 'react-router-dom';
import axios from 'axios';

function ProductDetail({ token }) {
  const { id } = useParams();
  const location = useLocation();
  const [product, setProduct] = useState(null);
  const [quantity, setQuantity] = useState(1);
  const [selectedColor, setSelectedColor] = useState('');
  const [selectedSize, setSelectedSize] = useState('');
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [selectedImage, setSelectedImage] = useState('');
  const [expandedSection, setExpandedSection] = useState(null);
  const [wishlist, setWishlist] = useState(false);
  const [relatedProducts, setRelatedProducts] = useState([]);
  const navigate = useNavigate();

  useEffect(() => {
    fetchProduct();
  }, [id]);

  const fetchProduct = async () => {
    try {
      console.log('Fetching product with ID:', id);
      console.log('Request URL: /api/products/' + id);
      const res = await axios.get(`/api/products/${id}`);
      console.log('Product fetched successfully:', res.data);
      setProduct(res.data);
      setSelectedImage(res.data.media?.featured || `/products/${res.data._id}.jpg`);
      if (res.data.variants && res.data.variants.length > 0) {
        setSelectedColor(res.data.variants[0].color);
        if (res.data.variants[0].sizes && res.data.variants[0].sizes.length > 0) {
          setSelectedSize(res.data.variants[0].sizes[0]);
        }
      }
      fetchRelatedProducts(res.data.gender, res.data.category);
    } catch (err) {
      console.error('Error fetching product:', err);
      console.error('Error message:', err.message);
      console.error('Error response:', err.response?.data);
      console.error('Error status:', err.response?.status);
      setError('Product not found');
    } finally {
      setLoading(false);
    }
  };

  const fetchRelatedProducts = async (gender, category) => {
    try {
      const res = await axios.get('/api/products');
      const related = res.data
        .filter(p => p.gender === gender && p.category === category && p._id !== id)
        .slice(0, 4);
      setRelatedProducts(related);
    } catch (err) {
      console.log('Error fetching related products');
    }
  };

  const handleAddToCart = async (e) => {
    e.preventDefault();
    if (!token) {
      navigate('/login');
      return;
    }

    try {
      await axios.post('/api/cart/add',
        { productId: id, quantity: parseInt(quantity), size: selectedSize, color: selectedColor },
        { headers: { Authorization: `Bearer ${token}` } }
      );
      setSuccess('Added to cart!');
      setTimeout(() => setSuccess(''), 2000);
    } catch (err) {
      setError('Failed to add to cart');
    }
  };

  if (loading) return <div style={{ padding: '60px 50px', textAlign: 'center', fontFamily: 'Helvetica, Arial, sans-serif' }}>Loading...</div>;
  if (error) return <div style={{ padding: '60px 50px', textAlign: 'center', fontFamily: 'Helvetica, Arial, sans-serif', color: '#d32f2f' }}>{error}</div>;
  if (!product) return <div style={{ padding: '60px 50px', textAlign: 'center', fontFamily: 'Helvetica, Arial, sans-serif', color: '#d32f2f' }}>Product not found</div>;

  const currentVariant = product.variants?.find(v => v.color === selectedColor);
  const sizes = currentVariant?.sizes || [];

  // Generate breadcrumb
  const breadcrumb = [
    'THE RAW',
    product.gender?.toUpperCase(),
    product.category?.toUpperCase(),
    product.name?.toUpperCase()
  ].filter(Boolean).join(' / ');

  return (
    <div style={{ backgroundColor: '#fff', fontFamily: 'Helvetica, Arial, sans-serif' }}>
      {/* Breadcrumb */}
      <div style={{
        padding: '30px 50px',
        fontSize: '11px',
        fontWeight: '300',
        letterSpacing: '0.5px',
        color: '#000',
        borderBottom: '1px solid #f0f0f0'
      }}>
        {breadcrumb}
      </div>

      {/* Main Product Layout */}
      <div style={{
        display: 'grid',
        gridTemplateColumns: '1fr 1.2fr 200px',
        gap: '60px',
        padding: '60px 50px',
        alignItems: 'start'
      }}>
        {/* Left - Images */}
        <div>
          <div style={{
            aspectRatio: '1000 / 1400',
            backgroundColor: '#f9f9f9',
            marginBottom: '30px',
            overflow: 'hidden',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center'
          }}>
            <img
              src={selectedImage}
              alt={product.name}
              style={{
                width: '100%',
                height: '100%',
                objectFit: 'cover'
              }}
            />
          </div>

          {/* Thumbnail Gallery */}
          {product.media?.gallery && product.media.gallery.length > 0 && (
            <div style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(4, 1fr)',
              gap: '10px'
            }}>
              <div
                onClick={() => setSelectedImage(product.media.featured)}
                style={{
                  aspectRatio: '1',
                  backgroundColor: '#f9f9f9',
                  cursor: 'pointer',
                  border: selectedImage === product.media.featured ? '1px solid #000' : '1px solid #f0f0f0'
                }}
              >
                <img
                  src={product.media.featured}
                  alt="Main"
                  style={{ width: '100%', height: '100%', objectFit: 'cover' }}
                />
              </div>
              {product.media.gallery.map((img, idx) => (
                <div
                  key={idx}
                  onClick={() => setSelectedImage(img)}
                  style={{
                    aspectRatio: '1',
                    backgroundColor: '#f9f9f9',
                    cursor: 'pointer',
                    border: selectedImage === img ? '1px solid #000' : '1px solid #f0f0f0'
                  }}
                >
                  <img
                    src={img}
                    alt={`Gallery ${idx}`}
                    style={{ width: '100%', height: '100%', objectFit: 'cover' }}
                  />
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Right - Product Info */}
        <div style={{ display: 'flex', flexDirection: 'column' }}>
          {/* Product Name and Price */}
          <div style={{ marginBottom: '40px' }}>
            <h1 style={{
              fontSize: '24px',
              fontWeight: '400',
              letterSpacing: '1px',
              color: '#000',
              margin: '0 0 15px 0',
              textTransform: 'uppercase'
            }}>
              {product.name}
            </h1>
            <p style={{
              fontSize: '16px',
              fontWeight: '400',
              letterSpacing: '0.5px',
              color: '#000',
              margin: '0'
            }}>
              ${product.price}
            </p>
          </div>

          {/* Color Selection */}
          {product.variants && product.variants.length > 0 && (
            <div style={{ marginBottom: '40px' }}>
              <label style={{
                display: 'block',
                fontSize: '11px',
                fontWeight: '400',
                letterSpacing: '0.5px',
                textTransform: 'uppercase',
                color: '#000',
                marginBottom: '15px'
              }}>
                {selectedColor}
              </label>
              <div style={{ display: 'flex', gap: '8px', flexWrap: 'wrap' }}>
                {product.variants.map((variant) => (
                  <button
                    key={variant.color}
                    type="button"
                    onClick={() => setSelectedColor(variant.color)}
                    style={{
                      width: '20px',
                      height: '20px',
                      padding: '0',
                      border: selectedColor === variant.color ? '2px solid #000' : '1px solid #ccc',
                      backgroundColor: variant.color === 'BLACK' ? '#000' : variant.color === 'WHITE' ? '#fff' : variant.color?.toLowerCase(),
                      cursor: 'pointer',
                      transition: 'all 0.3s'
                    }}
                    title={variant.color}
                  />
                ))}
              </div>
            </div>
          )}

          {/* Always Show Description */}
          <div style={{ marginBottom: '40px', borderTop: '1px solid #f0f0f0', paddingTop: '40px', borderBottom: '1px solid #f0f0f0', paddingBottom: '20px' }}>
            <h3 style={{
              fontSize: '11px',
              fontWeight: '400',
              letterSpacing: '0.5px',
              textTransform: 'uppercase',
              color: '#000',
              marginBottom: '15px'
            }}>
              DETAILS & DESCRIPTION
            </h3>
            <div style={{
              fontSize: '13px',
              fontWeight: '300',
              lineHeight: '1.8',
              letterSpacing: '0.3px',
              color: '#666'
            }}>
              {product.details?.description || product.description || 'Premium quality crafted with attention to detail.'}
            </div>
          </div>

          {/* Materials - Always Show */}
          {product.details?.materials && product.details.materials.length > 0 && (
            <div style={{ marginBottom: '40px', borderTop: '1px solid #f0f0f0', paddingTop: '20px', borderBottom: '1px solid #f0f0f0', paddingBottom: '20px' }}>
              <h3 style={{
                fontSize: '11px',
                fontWeight: '400',
                letterSpacing: '0.5px',
                textTransform: 'uppercase',
                color: '#000',
                marginBottom: '15px'
              }}>
                MATERIALS
              </h3>
              <div style={{
                fontSize: '13px',
                fontWeight: '300',
                lineHeight: '1.8',
                letterSpacing: '0.3px',
                color: '#666'
              }}>
                {product.details.materials.map((material, idx) => (
                  <div key={idx}>{material.type}: {material.value}%</div>
                ))}
              </div>
            </div>
          )}

          {/* Origin - Always Show */}
          {product.details?.origin && (
            <div style={{ marginBottom: '40px', borderBottom: '1px solid #f0f0f0', paddingBottom: '20px' }}>
              <h3 style={{
                fontSize: '11px',
                fontWeight: '400',
                letterSpacing: '0.5px',
                textTransform: 'uppercase',
                color: '#000',
                marginBottom: '15px'
              }}>
                ORIGIN
              </h3>
              <div style={{
                fontSize: '13px',
                fontWeight: '300',
                lineHeight: '1.8',
                letterSpacing: '0.3px',
                color: '#666'
              }}>
                {product.details.origin}
              </div>
            </div>
          )}

          {/* Wishlist */}
          <button
            onClick={() => setWishlist(!wishlist)}
            style={{
              background: 'none',
              border: 'none',
              padding: '0',
              fontSize: '20px',
              cursor: 'pointer',
              marginBottom: '40px',
              color: wishlist ? '#000' : '#999',
              transition: 'color 0.3s'
            }}
          >
            ♡
          </button>

          {/* Style With Section */}
          {relatedProducts.length > 0 && (
            <div style={{ marginTop: '60px' }}>
              <h3 style={{
                fontSize: '11px',
                fontWeight: '400',
                letterSpacing: '0.5px',
                textTransform: 'uppercase',
                color: '#000',
                marginBottom: '20px'
              }}>
                STYLE WITH
              </h3>
              <div style={{
                display: 'grid',
                gridTemplateColumns: 'repeat(2, 1fr)',
                gap: '15px'
              }}>
                {relatedProducts.map((prod) => (
                  <div
                    key={prod._id}
                    onClick={() => navigate(`/product/${prod._id}`)}
                    style={{
                      cursor: 'pointer',
                      overflow: 'hidden'
                    }}
                  >
                    <div style={{
                      aspectRatio: '1',
                      backgroundColor: '#f9f9f9',
                      marginBottom: '10px',
                      overflow: 'hidden'
                    }}>
                      <img
                        src={prod.media?.featured || `/products/${prod._id}.jpg`}
                        alt={prod.name}
                        style={{
                          width: '100%',
                          height: '100%',
                          objectFit: 'cover'
                        }}
                      />
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>

        {/* Right Sidebar - Size and Add to Cart */}
        <div style={{
          width: '140px'
        }}>
          {/* Size Dropdown */}
          <div style={{ marginBottom: '30px' }}>
            <label style={{
              display: 'block',
              fontSize: '11px',
              fontWeight: '400',
              letterSpacing: '0.5px',
              textTransform: 'uppercase',
              color: '#999',
              marginBottom: '10px'
            }}>
              SIZE
            </label>
            <select
              value={selectedSize}
              onChange={(e) => setSelectedSize(e.target.value)}
              style={{
                width: '100%',
                padding: '10px 12px',
                border: '1px solid #f0f0f0',
                fontSize: '12px',
                fontFamily: 'Helvetica, Arial, sans-serif',
                fontWeight: '300',
                color: '#000',
                backgroundColor: '#fff',
                cursor: 'pointer'
              }}
            >
              <option value="">Select Size</option>
              {sizes.map((size) => (
                <option key={size} value={size}>
                  {size}
                </option>
              ))}
            </select>
          </div>

          {/* Add to Cart Button */}
          <button
            onClick={handleAddToCart}
            style={{
              width: '100%',
              padding: '18px 0',
              backgroundColor: '#000',
              color: '#fff',
              border: 'none',
              fontSize: '14px',
              fontFamily: 'Helvetica, Arial, sans-serif',
              fontWeight: '400',
              letterSpacing: '1px',
              textTransform: 'uppercase',
              cursor: 'pointer',
              transition: 'opacity 0.3s'
            }}
            onMouseEnter={(e) => e.target.style.opacity = '0.8'}
            onMouseLeave={(e) => e.target.style.opacity = '1'}
          >
            ADD +
          </button>

          {/* Messages */}
          {success && (
            <div style={{
              marginTop: '15px',
              padding: '10px',
              backgroundColor: '#f0f0f0',
              fontSize: '11px',
              color: '#000',
              letterSpacing: '0.5px',
              textAlign: 'center'
            }}>
              {success}
            </div>
          )}
          {error && (
            <div style={{
              marginTop: '15px',
              padding: '10px',
              backgroundColor: '#ffebee',
              fontSize: '11px',
              color: '#d32f2f',
              letterSpacing: '0.5px',
              textAlign: 'center'
            }}>
              {error}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

export default ProductDetail;
